insert into cotdl.tbl_piijob 
select jobid, cast(version as INTEGER)+1, jobname, system, policy_id, keymap_id, jobtype, runtype, calendar, time, cronval, confirmflag, status, 'CHECKOUT' as phase, job_owner_id1, job_owner_name1, job_owner_id2, job_owner_name2, job_owner_id3, job_owner_name3, enddate, regdate, NOW() as upddate, reguserid, upduserid
